var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"CRF의 억제력이 사라졌군요. 역장의 영향권은 벗어난 듯 합니다.","JPN":"CRFの抑止力が消えました。力場の影響からは完全に抜け出せたようです。","ENG":"The CRF deterrence is gone. I believe we have stepped out of the stasis field.","TWN":"CRF的抑制力消失了。似乎已經脫離了力場的影響範圍。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"후아-","JPN":"はあ……","ENG":"Huah!","TWN":"呼——"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어때요? 안 불편했나요?","JPN":"どうですか？　大丈夫でしたか？","ENG":"How was it? Did you feel any discomfort?","TWN":"怎樣？沒有覺得不舒服吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 신기할 정도로 흔들리지 않더군.","JPN":"ああ。不思議なほど揺れを感じなかった。","ENG":"No. It was surprisingly very stable.","TWN":"是啊，真是令人驚訝的平穩呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"자주 해봤거든요. 양동이 물 안 쏟고 달리기 같은 거.","JPN":"よくやってたんです。バケツの水をこぼさずに走ったり。","ENG":"I've done it often. You know, like, running with a bucket of water and trying not to spill it.","TWN":"這種事我經常做喔，比如說挑水的時候不讓水灑出來。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"생각보다 엄청 달렸네요. 직경이 6km나 되는 방해 역장이라니.","JPN":"思ったより遠くまで来ましたね。直径が6kmもある力場だったなんて。","ENG":"Come to think of it, we ran pretty far. Didn't think the stasis field would have a diameter of 6 km.","TWN":"比我想像中的還要遠啊……直徑竟然會有足足6公里……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"게다가 역장을 가동시킨 기물이 보이지 않으니, 부술 수도 없겠어요.","JPN":"それに、力場を稼働した器物がどこにあるかもわからないから、壊すこともできなさそう。","ENG":"Also, I haven't spotted the object that activated it, so I can't even destroy it.","TWN":"而且我看不到發生力場的裝置，沒辦法破壞……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"쉽게 찾을 수 없는 곳에 심어뒀을 겁니다. 펠릭스가 조종하던 그림자들이 설치를 도왔을 지도 모르죠.","JPN":"簡単には見つからない場所に隠してあるでしょう。フェリックスが操っていたシャドウたちが設置したのかもしれません。","ENG":"They must have planted it somewhere hard to find. Or perhaps the Shadows that Felix controlled helped plant it.","TWN":"應該是被他們藏在了隱蔽的地方。也許是緋莉克絲所操控的暗影所為。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역장은 벗어났지만, 전파 방해가 여전히 심하군.","JPN":"力場からは離れられたが、まだ電波妨害が激しい。","ENG":"We've escaped the stasis field, but the radio is still jammed.","TWN":"雖然脫離了力場，但干擾依然很嚴重。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지원 요청은 미뤄두고 먼저 우리 직원과 합류하는 게 좋겠어.","JPN":"支援要請は後にして、まずは社員たちと合流しよう。","ENG":"We should delay calling for reinforcements and regroup with my employee first.","TWN":"支援請求先放一邊，最好先和我們的員工會合。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시로코바가 무사히 탈출했다면 접선지에서 기다리고 있을 겁니다.","JPN":"シロコバが無事脱出していれば、待ち合わせ場所で待っているはずです。","ENG":"If Shirokova made it out safe, she should be waiting for us at the rendezvous point.","TWN":"如果西羅科娃順利逃脫的話，會在接頭地點等我們。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"발키리가 거기 있다는 거지? 좋아. 서두르자.","JPN":"ヴァルキリーがそこにいるってことだね。よし、急ごう。","ENG":"And that's where Valkyrie is? All right. Let's go.","TWN":"女武神在那裡，對吧？好，趕緊行動吧～"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"늦었군.","JPN":"手遅れか。","ENG":"We're too late.","TWN":"……我們還是晚了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응…?","JPN":"え……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"솔로베를 감싼다","JPN":"ソロベーをかばう","ENG":"Cover Solovey","TWN":"保護蘇羅薇"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…꺄앗?!","JPN":"…きゃあっ！？","ENG":"...Kyaah?!","TWN":"……哎呀？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"안돼…","JPN":"ダメ……","ENG":"No...","TWN":"不要……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사장님?!","JPN":"社長！？","ENG":"Boss?!","TWN":"老闆！？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"관리자!","JPN":"管理者！","ENG":"Administrator!","TWN":"管理者！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저런.","JPN":"やれやれ。","ENG":"Oh, my.","TWN":"喔？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"제 사선을 가로막다니. 놀랄 정도로 감이 좋으시군요.","JPN":"私の死線を防ぐとは……驚くほど鋭い勘ですね。","ENG":"You have keen senses being able to block my line of fire.","TWN":"竟然擋在了我的槍口面前，真是讓人驚訝的直覺。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};